//
//  HOW mlc4j IS GENERATED (the correct way):
//
//  mlc4j is NOT copied from the repo manually.
//  It is GENERATED by the MLC build pipeline:
//
//    # Install MLC-LLM Python package
//    pip install mlc-llm
//
//    # Place mlc-package-config.json in project root (already done)
//    # Run the packager — this compiles .so libs + generates dist/lib/mlc4j
//    python3 -m mlc_llm package
//
//  After that:
//    dist/lib/mlc4j    ← Android library module (the mlc4j module)
//    dist/bundle/      ← compiled model weights
//
//  Then in settings.gradle uncomment:
//    include ':mlc4j'
//    project(':mlc4j').projectDir = file('dist/lib/mlc4j')
//
//  In app/build.gradle uncomment:
//    implementation project(':mlc4j')
//
//  Below set:  MLC_AVAILABLE = true
//  Uncomment:  the 3 import lines
// ============================================================

