        if (!MLC_AVAILABLE || currentState != EngineState.READY)
            return@withContext fallbackResponse(prompt)

        setState(EngineState.GENERATING)
        val sb = StringBuilder()
        try {
            // val messages = mutableListOf<ChatCompletionMessage>()
            // history.forEach { (u, a) ->
            //     messages += ChatCompletionMessage(
            //         role = OpenAIProtocol.ChatCompletionRole.user,
            //         content = OpenAIProtocol.ChatCompletionMessageContent(text = u)
            //     )
            //     messages += ChatCompletionMessage(
            //         role = OpenAIProtocol.ChatCompletionRole.assistant,
            //         content = a
            //     )
            // }
            // messages += ChatCompletionMessage(
            //     role = OpenAIProtocol.ChatCompletionRole.user,
            //     content = OpenAIProtocol.ChatCompletionMessageContent(text = prompt)
            // )
            // val responses = engine.chat.completions.create(
            //     messages = messages,
            //     stream_options = OpenAIProtocol.StreamOptions(include_usage = true)
            // )
            // for (res in responses) {
            //     for (choice in res.choices) {
            //         choice.delta.content?.let { c ->
            //             val token = c.asText()
            //             sb.append(token)
            //             scope.launch { onTokenStream?.invoke(token) }
            //         }
            //         // AppViewModel also checks finish_reason == "length"
            //         choice.finish_reason?.let { reason ->
            //             if (reason == "length") sb.append(" [truncated]")
            //         }
            //     }
            //     // Usage stats (tokens/sec) from res.usage
            //     res.usage?.let { scope.launch {
            //         // update report label: it.extra?.asTextLabel()
            //     }}
            // }
        } catch (e: Exception) {
            Log.e(TAG, "Generate error: ${e.message}")
            setState(EngineState.READY)
            return@withContext "Error: ${e.message}"
